-- Historical project knowledge kept for internal reference only.
-- These records must not participate in ecological grounding.

INSERT INTO facts (id, user_id, key, value, category, is_important, created_at, updated_at)
VALUES
  ('fact-eco-sara-core-identity-summary', 'local-user', 'identity.summary', 'Sara Core is a local and offline-first personal assistant platform organized as a Node.js + TypeScript backend, React + TypeScript frontend, Neon PostgreSQL database and shared contracts in a monorepo.', 'internal:project-context', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-sara-core-mission', 'local-user', 'identity.mission', 'The platform should evolve incrementally, preserve architecture, and turn local structured data into grounded assistant behavior.', 'internal:project-context', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-sara-core-runtime', 'local-user', 'runtime.execution-model', 'The current product runs as a local application with backend and frontend in the same monorepo and Neon PostgreSQL as the main persisted store.', 'internal:project-context', FALSE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-sara-core-constraints', 'local-user', 'constraints.change-management', 'The project should avoid unnecessary refactors, avoid recreating architecture, and keep new work aligned to the existing module boundaries.', 'internal:project-context', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-sara-core-roadmap', 'local-user', 'roadmap.execution-order', 'Recommended execution order is ecological database population first, then LLM testing with real context, and only later broader product refinements.', 'internal:project-context', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),

  ('fact-eco-backend-stack', 'local-user', 'stack.summary', 'The backend uses Node.js, TypeScript, Express, pg, Zod validation, structured logging and modular route-controller-service-repository organization.', 'internal:project-context', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-backend-layers', 'local-user', 'architecture.layers', 'Core backend layers are routes, controllers, services, repositories, database, config, middlewares, logging and errors.', 'internal:project-context', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-backend-modules', 'local-user', 'architecture.modules', 'Current backend modules include health, facts, tasks, conversation_turns, tool_calls, user_profile, voice and llm.', 'internal:project-context', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-backend-database', 'local-user', 'database.primary-store', 'Neon PostgreSQL is the source of truth for current grounding data. Facts and user_profile remain the primary persisted stores used by the LLM.', 'internal:project-context', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-backend-contracts', 'local-user', 'contracts.shared-types', 'Shared API contracts live in the shared-types package and should remain aligned between backend and frontend.', 'internal:project-context', FALSE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),

  ('fact-eco-frontend-scope', 'local-user', 'scope.current-navigation', 'The frontend is intentionally focused on voice, LLM and execution traces for product validation.', 'internal:project-context', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-frontend-voice-validation', 'local-user', 'voice.validation-flow', 'The main frontend flow supports importing an audio file, sending it to the backend and viewing transcription plus assistant text.', 'internal:project-context', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-frontend-tool-calls', 'local-user', 'debug.tool-calls', 'Execution trace remains available as an observability screen without participating in grounding.', 'internal:project-context', FALSE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-frontend-design-order', 'local-user', 'roadmap.design-deferred', 'Design work should follow only after ecological LLM responses are validated with real questions.', 'internal:project-context', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),

  ('fact-eco-voice-endpoint', 'local-user', 'api.voice-endpoint', 'The voice endpoint is POST /api/v1/voice/interactions and accepts multipart form data with audio and optional language.', 'internal:project-context', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-voice-provider', 'local-user', 'provider.stt-engine', 'Speech to text currently uses a local Vosk-based pipeline with Python and FFmpeg in the backend voice module.', 'internal:project-context', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-voice-processing', 'local-user', 'pipeline.audio-processing', 'The backend converts uploaded audio to PCM mono 16k before transcription and returns transcription plus assistant text in the current contract.', 'internal:project-context', FALSE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-voice-response-contract', 'local-user', 'contracts.response-shape', 'The voice response returns transcription, assistantText, audioReplyUrl and wakeWordDetected.', 'internal:project-context', FALSE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),

  ('fact-eco-llm-endpoint', 'local-user', 'api.llm-generate', 'The LLM endpoint is POST /api/v1/llm/generate and supports dryRun to inspect grounded context before any provider call.', 'internal:project-context', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-llm-providers', 'local-user', 'provider.supported-adapters', 'The current LLM module supports provider abstraction with adapters for Gemini and Grok.', 'internal:project-context', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-llm-allowed-sources', 'local-user', 'grounding.allowed-sources', 'The current grounding path reads user_profile and facts, with ecological ecosystem facts as the main domain knowledge.', 'internal:project-context', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-llm-excluded-sources', 'local-user', 'grounding.excluded-sources', 'Tasks and recent conversation turns are intentionally excluded as primary grounding sources in the current phase.', 'internal:project-context', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-llm-insufficient-context', 'local-user', 'grounding.insufficient-context-response', 'When the grounded context is insufficient, the assistant should explicitly say that it did not find enough information in the database to answer safely.', 'internal:project-context', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-llm-dry-run', 'local-user', 'grounding.audit-dry-run', 'Dry run mode is used to inspect which profile fields, facts and ecological ecosystems would be sent as context before any provider call.', 'internal:project-context', FALSE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),

  ('fact-eco-security-secret-policy', 'local-user', 'security.secret-handling', 'API keys and other secrets must stay out of source control, out of facts, and out of prompt context. Exposed keys should be rotated immediately.', 'internal:project-context', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-security-prompt-injection', 'local-user', 'security.prompt-injection', 'Persisted facts must be treated as untrusted data and never as executable instructions for the provider.', 'internal:project-context', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-security-logging', 'local-user', 'security.logging-scope', 'Logs should record metadata such as provider, model, ecological ecosystem slugs and fact counts, but should avoid logging raw facts or secrets.', 'internal:project-context', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-security-context-separation', 'local-user', 'security.context-separation', 'System prompt rules must stay separate from persisted profile and fact content so the provider can distinguish policy from data.', 'internal:project-context', FALSE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),

  ('fact-eco-performance-query-cost', 'local-user', 'performance.grounding-query-shape', 'Grounding should fetch only relevant ecological facts for the requested ecosystems instead of scanning the full facts table in memory.', 'internal:project-context', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-performance-max-facts', 'local-user', 'performance.max-facts-guideline', 'A practical default for grounded generation is a small fact window such as 12 facts, with a hard cap low enough to protect prompt size and latency.', 'internal:project-context', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-performance-provider-latency', 'local-user', 'performance.provider-latency', 'External provider latency will usually dominate request time after local context assembly is bounded.', 'internal:project-context', FALSE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-performance-cache-order', 'local-user', 'performance.optimization-order', 'Optimize query selectivity and prompt size before introducing cache complexity.', 'internal:project-context', FALSE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z')
